#!/usr/bin/env node
/**
 * Generates src/scene/sky/star-catalog.ts from the HYG stellar database.
 *
 * Usage:
 *   node scripts/generate-star-catalog.mjs [path-to-hygdata_v41.csv]
 *
 * Without an argument the script downloads the catalog from the astronexus
 * HYG-Database repository. The generated file is committed so builds and
 * runtime never need the network. See docs/ASSETS.md for provenance and
 * license (HYG v4.1, CC BY-SA 4.0, https://github.com/astronexus/HYG-Database).
 */

import { mkdtempSync, readFileSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const HYG_URL =
  "https://raw.githubusercontent.com/astronexus/HYG-Database/main/hyg/CURRENT/hygdata_v41.csv";
const MAGNITUDE_LIMIT = 5.5;
const NAMED_STAR_MAGNITUDE_LIMIT = 2.1;

/** Minimal CSV line parser that honors double-quoted fields. */
function parseCsvLine(line) {
  const fields = [];
  let current = "";
  let inQuotes = false;
  for (let i = 0; i < line.length; i += 1) {
    const char = line[i];
    if (inQuotes) {
      if (char === '"') {
        if (line[i + 1] === '"') {
          current += '"';
          i += 1;
        } else {
          inQuotes = false;
        }
      } else {
        current += char;
      }
    } else if (char === '"') {
      inQuotes = true;
    } else if (char === ",") {
      fields.push(current);
      current = "";
    } else {
      current += char;
    }
  }
  fields.push(current);
  return fields;
}

async function loadCsv() {
  const argPath = process.argv[2];
  if (argPath) return readFileSync(argPath, "utf8");
  console.log(`Downloading ${HYG_URL} …`);
  const response = await fetch(HYG_URL);
  if (!response.ok) throw new Error(`Download failed: HTTP ${response.status}`);
  const text = await response.text();
  const cachePath = join(mkdtempSync(join(tmpdir(), "hyg-")), "hygdata_v41.csv");
  writeFileSync(cachePath, text);
  console.log(`Cached at ${cachePath}`);
  return text;
}

const csv = await loadCsv();
const lines = csv.split("\n");
const header = parseCsvLine(lines[0]);
const column = (name) => {
  const index = header.indexOf(name);
  if (index < 0) throw new Error(`Missing column ${name}`);
  return index;
};

const idColumn = column("id");
const properColumn = column("proper");
const raColumn = column("ra"); // hours
const decColumn = column("dec"); // degrees
const magColumn = column("mag");
const ciColumn = column("ci");

const stars = [];
for (let i = 1; i < lines.length; i += 1) {
  const line = lines[i];
  if (!line) continue;
  const fields = parseCsvLine(line);
  if (fields[idColumn] === "0") continue; // the Sun
  const mag = Number(fields[magColumn]);
  if (!Number.isFinite(mag) || mag > MAGNITUDE_LIMIT) continue;
  const raHours = Number(fields[raColumn]);
  const decDeg = Number(fields[decColumn]);
  if (!Number.isFinite(raHours) || !Number.isFinite(decDeg)) continue;
  const ci = Number(fields[ciColumn]);
  stars.push({
    raDeg: raHours * 15,
    decDeg,
    mag,
    colorIndex: Number.isFinite(ci) ? ci : 0.5,
    proper: fields[properColumn]?.trim() ?? "",
  });
}

stars.sort((a, b) => a.mag - b.mag);

const round = (value, decimals) => Number(value.toFixed(decimals));
const raList = stars.map((star) => round(star.raDeg, 4));
const decList = stars.map((star) => round(star.decDeg, 4));
const magList = stars.map((star) => round(star.mag, 2));
const ciList = stars.map((star) => round(star.colorIndex, 2));
const namedStars = stars
  .map((star, index) => ({ index, name: star.proper, mag: star.mag }))
  .filter((star) => star.name && star.mag <= NAMED_STAR_MAGNITUDE_LIMIT);

const generated = `// Generated by scripts/generate-star-catalog.mjs — do not edit by hand.
// Source: HYG stellar database v4.1 (https://github.com/astronexus/HYG-Database),
// license CC BY-SA 4.0. Subset: visual magnitude <= ${MAGNITUDE_LIMIT}, sorted brightest first.
// Frames/units: right ascension and declination are J2000 (EQJ) degrees.

export const STAR_COUNT = ${stars.length};

export const STAR_RA_DEG: readonly number[] = [${raList.join(",")}];

export const STAR_DEC_DEG: readonly number[] = [${decList.join(",")}];

export const STAR_MAG: readonly number[] = [${magList.join(",")}];

export const STAR_COLOR_INDEX: readonly number[] = [${ciList.join(",")}];

/** [index into the arrays above, proper name] for the brightest named stars. */
export const STAR_NAMES: readonly (readonly [number, string])[] = [
${namedStars.map((star) => `  [${star.index}, ${JSON.stringify(star.name)}],`).join("\n")}
];
`;

const outPath = join(
  dirname(fileURLToPath(import.meta.url)),
  "..",
  "src",
  "scene",
  "sky",
  "star-catalog.ts",
);
writeFileSync(outPath, generated);
console.log(
  `Wrote ${outPath}: ${stars.length} stars (mag <= ${MAGNITUDE_LIMIT}), ${namedStars.length} named.`,
);
